const reply = $input.first().json.choices[0].message.content;
const body = $('Webhook').first().json.body;
const question = body.message;
const name = body.name || 'Desconocido';
const whatsapp = body.whatsapp || 'No indicado';

return [{
  json: {
    reply,
    question,
    whatsappText: `🔔 *Nuevo lead — automatiza.com.pa*\n\n👤 *Nombre:* ${name}\n📱 *WhatsApp:* ${whatsapp}\n\n💬 *Pregunta:* ${question}\n\n🤖 *Respuesta IA:* ${reply}`
  }
}];
